class Solution {
public:
    bool canGroup(vector<int>& hand, int groupSize) {
        int n = hand.size();
        if (n % groupSize != 0) return false;

        unordered_map<int, int> freq;
        for (int x : hand) freq[x]++;


        priority_queue<int, vector<int>, greater<int>> minHeap;
        for (auto &p : freq) minHeap.push(p.first);

        while (!minHeap.empty()) {
            int start = minHeap.top();  


            for (int card = start; card < start + groupSize; card++) {

                if (freq[card] == 0)
                    return false;  

                freq[card]--;


                if (freq[card] == 0) {
                    if (card != minHeap.top())
                        return false;  

                    minHeap.pop();  
                }
            }
        }

        return true;
    }
};

