// typedef long long ll;

typedef struct {
    ll *a;
    int size;
} MinHeap;

void heap_swap(ll *a, ll *b) {
    ll t = *a; *a = *b; *b = t;
}

void heap_up(MinHeap *h, int i) {
    while (i > 0) {
        int p = (i - 1) / 2;
        if (h->a[p] <= h->a[i]) break;
        heap_swap(&h->a[p], &h->a[i]);
        i = p;
    }
}

void heap_down(MinHeap *h, int i) {
    int n = h->size;
    while (1) {
        int l = 2*i + 1, r = 2*i + 2, m = i;
        if (l < n && h->a[l] < h->a[m]) m = l;
        if (r < n && h->a[r] < h->a[m]) m = r;
        if (m == i) break;
        heap_swap(&h->a[m], &h->a[i]);
        i = m;
    }
}

ll heap_top(MinHeap *h) {
    return h->a[0];
}

void heap_pop(MinHeap *h) {
    h->a[0] = h->a[h->size - 1];
    h->size--;
    heap_down(h, 0);
}

int cmp_ll(const void *a, const void *b) {
    ll x = *(ll*)a, y = *(ll*)b;
    return (x > y) - (x < y);
}

int canGroup(ll *hand, int N, int groupSize) {
    qsort(hand, N, sizeof(ll), cmp_ll);

    ll *vals = malloc(N * sizeof(ll));
    int *cnt = malloc(N * sizeof(int));
    int m = 0;

    vals[0] = hand[0];
    cnt[0] = 1;
    m = 1;

    for (int i = 1; i < N; i++) {
        if (hand[i] == vals[m-1]) cnt[m-1]++;
        else {
            vals[m] = hand[i];
            cnt[m] = 1;
            m++;
        }
    }

    MinHeap h;
    h.a = malloc(m * sizeof(ll));
    h.size = m;
    for (int i = 0; i < m; i++) h.a[i] = vals[i];
    for (int i = m/2; i >= 0; i--) heap_down(&h, i);

    while (h.size) {
        ll start = heap_top(&h);
        for (int k = 0; k < groupSize; k++) {
            ll need = start + k;

            int pos = -1, l = 0, r = m - 1;
            while (l <= r) {
                int mid = (l + r) / 2;
                if (vals[mid] == need) { pos = mid; break; }
                if (vals[mid] < need) l = mid + 1;
                else r = mid - 1;
            }
            if (pos == -1 || cnt[pos] == 0) {
                free(vals); free(cnt); free(h.a);
                return 0;
            }

            cnt[pos]--;
            if (cnt[pos] == 0) {
                if (need != heap_top(&h)) {
                    free(vals); free(cnt); free(h.a);
                    return 0;
                }
                heap_pop(&h);
            }
        }
    }

    free(vals);
    free(cnt);
    free(h.a);
    return 1;
}

