class Solution {
    public boolean canGroup(int[] hand, int groupSize) {
        int n = hand.length;
        if (n % groupSize != 0) return false;

        Map<Integer, Integer> freq = new HashMap<>();
        for (int x : hand) freq.put(x, freq.getOrDefault(x, 0) + 1);

        PriorityQueue<Integer> minHeap = new PriorityQueue<>(freq.keySet());

        while (!minHeap.isEmpty()) {
            int start = minHeap.peek();
            for (int card = start; card < start + groupSize; card++) {
                if (!freq.containsKey(card) || freq.get(card) == 0) return false;
                freq.put(card, freq.get(card) - 1);
                if (freq.get(card) == 0) {
                    if (card != minHeap.peek()) return false;
                    minHeap.poll();
                }
            }
        }
        return true;
    }
}

