class MinHeap {
    constructor(arr = []) {
        this.heap = arr;
        this.build();
    }
    build() {
        for (let i = Math.floor(this.heap.length / 2); i >= 0; i--) this.down(i);
    }
    push(x) {
        this.heap.push(x);
        this.up(this.heap.length - 1);
    }
    pop() {
        if (this.heap.length === 1) return this.heap.pop();
        const top = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.down(0);
        return top;
    }
    peek() {
        return this.heap[0];
    }
    size() {
        return this.heap.length;
    }
    up(i) {
        while (i > 0) {
            const p = Math.floor((i - 1) / 2);
            if (this.heap[p] <= this.heap[i]) break;
            [this.heap[p], this.heap[i]] = [this.heap[i], this.heap[p]];
            i = p;
        }
    }
    down(i) {
        const n = this.heap.length;
        while (true) {
            let l = 2 * i + 1, r = 2 * i + 2, s = i;
            if (l < n && this.heap[l] < this.heap[s]) s = l;
            if (r < n && this.heap[r] < this.heap[s]) s = r;
            if (s === i) break;
            [this.heap[s], this.heap[i]] = [this.heap[i], this.heap[s]];
            i = s;
        }
    }
}

class Solution {
    canGroup(hand, groupSize) {
        const n = hand.length;
        if (n % groupSize !== 0) return false;

        const freq = new Map();
        for (const x of hand) freq.set(x, (freq.get(x) || 0) + 1);

        const heap = new MinHeap(Array.from(freq.keys()));

        while (heap.size()) {
            const start = heap.peek();
            for (let card = start; card < start + groupSize; card++) {
                if (!freq.has(card) || freq.get(card) === 0) return false;
                freq.set(card, freq.get(card) - 1);
                if (freq.get(card) === 0) {
                    if (card !== heap.peek()) return false;
                    heap.pop();
                }
            }
        }
        return true;
    }
}
